(function () {
  if (window.Html5Qrcode) {
    return;
  }

  function Html5Qrcode(elementId) {
    this.elementId = elementId;
    this.container = document.getElementById(elementId);
    this.video = null;
    this.stream = null;
    this.detector = null;
    this.frameRequest = null;
    this.running = false;
  }

  Html5Qrcode.prototype.start = async function (cameraConfig, config, onSuccess, onError) {
    if (!this.container) {
      throw new Error("QR container not found");
    }
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      throw new Error("Camera API unavailable");
    }
    if (!("BarcodeDetector" in window)) {
      throw new Error("BarcodeDetector unavailable");
    }

    this.detector = new window.BarcodeDetector({ formats: ["qr_code"] });
    this.container.innerHTML = "";

    this.video = document.createElement("video");
    this.video.setAttribute("playsinline", "true");
    this.video.muted = true;
    this.video.autoplay = true;
    this.video.style.width = "100%";
    this.video.style.height = "100%";
    this.video.style.objectFit = "cover";
    this.container.appendChild(this.video);

    const constraints = {
      audio: false,
      video: {
        facingMode: (cameraConfig && cameraConfig.facingMode) || "environment"
      }
    };

    this.stream = await navigator.mediaDevices.getUserMedia(constraints);
    this.video.srcObject = this.stream;
    await this.video.play();

    this.running = true;
    const fps = Math.max(2, Math.min((config && config.fps) || 10, 30));
    const delay = Math.round(1000 / fps);

    const scan = async () => {
      if (!this.running || !this.video || this.video.readyState < 2) {
        this.frameRequest = window.setTimeout(scan, delay);
        return;
      }

      try {
        const codes = await this.detector.detect(this.video);
        if (codes && codes.length > 0) {
          const value = codes[0].rawValue;
          if (value) {
            onSuccess(value);
            return;
          }
        }
      } catch (error) {
        if (typeof onError === "function") {
          onError(error && error.message ? error.message : String(error));
        }
      }

      this.frameRequest = window.setTimeout(scan, delay);
    };

    scan();
  };

  Html5Qrcode.prototype.stop = async function () {
    this.running = false;
    if (this.frameRequest) {
      window.clearTimeout(this.frameRequest);
      this.frameRequest = null;
    }
    if (this.video) {
      this.video.pause();
      this.video.srcObject = null;
    }
    if (this.stream) {
      this.stream.getTracks().forEach(function (track) {
        track.stop();
      });
      this.stream = null;
    }
  };

  Html5Qrcode.prototype.clear = async function () {
    if (this.container) {
      this.container.innerHTML = "";
    }
    this.video = null;
  };

  window.Html5Qrcode = Html5Qrcode;
})();
